package ru.memearena.battle.api; import io.swagger.v3.oas.annotations.Operation; import org.springframework.http.*; import org.springframework.web.bind.annotation.*; import ru.memearena.battle.application.BattleService; import java.util.UUID; @RestController @RequestMapping("/api/v1/battles") public class BattleController { private final BattleService service; public BattleController(BattleService service){this.service=service;} @GetMapping("/next") @Operation(summary="Get next battle") public ResponseEntity<NextBattleResponse> next(@RequestParam UUID userId){return service.next(userId).map(ResponseEntity::ok).orElseGet(()->ResponseEntity.noContent().build());} }
